const fs = require('fs');
const path = require('path');

// Function to generate package-lock.json
function generatePackageLock() {
  // Check if package.json exists
  const packageJsonPath = path.join(process.cwd(), 'package.json');
  if (!fs.existsSync(packageJsonPath)) {
    console.error('package.json does not exist. Please create one first.');
    return;
  }

  // Run npm install to generate or update package-lock.json
  const { exec } = require('child_process');
  exec('npm install', (error, stdout, stderr) => {
    if (error) {
      console.error(`Error executing npm install: ${error.message}`);
      return;
    }
    if (stderr) {
      console.error(`npm install stderr:\n${stderr}`);
      return;
    }
    console.log('package-lock.json generated successfully.');
  });
}

// Function to update package-lock.json
function updatePackageLock() {
  // Run npm update to ensure consistent versions across environments
  const { exec } = require('child_process');
  exec('npm update', (error, stdout, stderr) => {
    if (error) {
      console.error(`Error executing npm update: ${error.message}`);
      return;
    }
    if (stderr) {
      console.error(`npm update stderr:\n${stderr}`);
      return;
    }
    console.log('package-lock.json updated successfully.');
  });
}

// Usage
generatePackageLock(); // To generate or ensure package-lock.json is present
updatePackageLock();   // To maintain consistent versions in package-lock.json